	<div class="addEdit-block">
		<el-form
			class="add-update-preview"
			ref="ruleForm"
			:model="ruleForm"
			:rules="rules"
			label-width="180px"
		>
			<template >
				<template v-if="ruleForm.type=='个人'">
					<el-form-item class="input" v-if="type!='info'"  label="角色" prop="role">
						<el-select filterable v-model="ruleForm.role" placeholder="角色" @change="roleChange">
							<el-option v-for="item in roleList" :label="item.tableName" :value="item.roleName"></el-option>
						</el-select>
					</el-form-item>
					<el-form-item v-else class="input" label="角色" prop="role" >
						{{changeRoleName(ruleForm.role)}}
					</el-form-item>
				</template>
				<el-form-item class="input" v-if="type!='info'&&ruleForm.type=='个人'"  label="用户" prop="userid">
					<el-select filterable v-model="ruleForm.userid" placeholder="用户">
						<el-option v-for="item in userList" :label="item.account" :value="item.id"></el-option>
					</el-select>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="标题" prop="title" >
					<el-input v-model="ruleForm.title" placeholder="标题" clearable  :readonly="ro.title"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="标题" prop="title" >
					<el-input v-model="ruleForm.title" placeholder="标题" readonly></el-input>
				</el-form-item>
				<el-form-item class="select" v-if="type!='info'"  label="类型" prop="type" >
					<el-select :disabled="ro.type" v-model="ruleForm.type" placeholder="请选择类型"  filterable>
						<el-option
							v-for="(item,index) in typeOptions"
							v-bind:key="index"
							:label="item"
							:value="item">
						</el-option>
					</el-select>
				</el-form-item>
				<el-form-item v-else class="input" label="类型" prop="type" >
					<el-input v-model="ruleForm.type"
						placeholder="类型" readonly></el-input>
				</el-form-item>
				<el-form-item class="date" v-if="type!='info'" label="提醒时间" prop="remindtime" >
					<el-date-picker
						value-format="yyyy-MM-dd HH:mm:ss"
						v-model="ruleForm.remindtime" 
						type="datetime"
						:readonly="ro.remindtime"
						placeholder="提醒时间"
					></el-date-picker>
				</el-form-item>
				<el-form-item class="input" v-else-if="ruleForm.remindtime" label="提醒时间" prop="remindtime" >
					<el-input v-model="ruleForm.remindtime" placeholder="提醒时间" readonly></el-input>
				</el-form-item>
			</template>
			<el-form-item class="textarea" v-if="type!='info'" label="简介" prop="brief" >
				<el-input
					style="min-width: 200px; max-width: 600px;"
					type="textarea"
					:rows="8"
					placeholder="简介"
					v-model="ruleForm.brief" >
				</el-input>
			</el-form-item>
			<el-form-item v-else-if="ruleForm.brief" label="简介" prop="brief"  class="textBox">
				<span class="text">{{ruleForm.brief}}</span>
			</el-form-item>
			<el-form-item v-if="type!='info'" class="editorBox" label="内容" prop="content" >
				<editor 
					style="min-width: 200px; max-width: 600px;"
					v-model="ruleForm.content" 
					class="editor"
					myQuillEditor="content"
					action="file/upload">
				</editor>
			</el-form-item>
			<el-form-item v-else-if="ruleForm.content" label="内容" prop="content"  class="textBox">
