<script>
	export default {
		data() {
			return {
				id: '',
				type: '',
			
			
				ro:{
					userid : false,
					role : false,
					title : false,
					type : false,
					brief : false,
					content : false,
					remindtime : false,
				},
			
				ruleForm: {
					userid: '',
					role: '',
					title: '',
					type: '个人',
					brief: '',
					content: '',
					remindtime: '',
				},
				typeOptions: [],

				rules: {
					userid: [
						{ required: true, message: '发布人id不能为空', trigger: 'blur' },
					],
					role: [
					],
					title: [
						{ required: true, message: '标题不能为空', trigger: 'blur' },
					],
					type: [
					],
					brief: [
					],
					content: [
						{ required: true, message: '内容不能为空', trigger: 'blur' },
					],
					remindtime: [
					],
				},
				roleList: [],
				userList: [],
			};
		},
		props: ["parent"],
		computed: {
			sessionForm() {
				return JSON.parse(this.$storage.getObj('userForm'))
			},
			sessionTable() {
				return this.$storage.get('sessionTable')
			},



		},
		components: {
		},
		created() {
			this.roleList = this.$role.roleList
		},
		methods: {
			imgPreView(url){
				this.$parent.imgPreView(url)
			},
			// 下载
			download(file){
				window.open(`${file}`)
			},
			// 初始化
			init(id,type ) {
				if (id) {
					this.id = id;
					this.type = type;
				}
				if(this.type=='info'||this.type=='else'||this.type=='msg'){
					this.info(id);
				}else if(this.type=='logistics'){
					for(let x in this.ro) {
						this.ro[x] = true
					}
					this.logistics=false;
					this.info(id);
				}else if(this.type=='cross'){
					var obj = this.$storage.getObj('crossObj');
					for (var o in obj){
						if(o=='userid'){
							this.ruleForm.userid = obj[o];
							this.ro.userid = true;
							continue;
						}
						if(o=='role'){
							this.ruleForm.role = obj[o];
							this.ro.role = true;
							continue;
						}
						if(o=='title'){
							this.ruleForm.title = obj[o];
							this.ro.title = true;
							continue;
						}
						if(o=='type'){
							this.ruleForm.type = obj[o];
							this.ro.type = true;
							continue;
						}
						if(o=='brief'){
							this.ruleForm.brief = obj[o];
							this.ro.brief = true;
							continue;
						}
						if(o=='content'){
							this.ruleForm.content = obj[o];
							this.ro.content = true;
							continue;
						}
						if(o=='remindtime'){
							this.ruleForm.remindtime = obj[o];
							this.ro.remindtime = true;
							continue;
						}
					}
				}

				this.typeOptions = "个人,全局".split(',')
			
			},
			roleChange(e){
				this.$http({
					url: `${e}/accountList`,
					method: 'get'
				}).then(rs=>{
					this.userList = rs.data.data
				})
			},
			changeRoleName(role){
				for(let x in this.roleList) {
					if(this.roleList[x].roleName==role) {
						return this.roleList[x].tableName
					}
				}
			},
			// 多级联动参数

			async info(id) {
				await this.$http({
					url: `popupremind/info/${id}`,
					method: "get"
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.ruleForm = data.data;
						//解决前台上传图片后台不显示的问题
						let reg=new RegExp('../../../upload','g')//g代表全部
						this.ruleForm.content = this.ruleForm.content.replace(reg,'../../../springboot3okzy2q75/upload');
						this.roleChange(this.ruleForm.role)
					} else {
						this.$message.error(data.msg);
					}
				});
			},

			// 提交
			async onSubmit() {
					var objcross = this.$storage.getObj('crossObj');
					await this.$refs["ruleForm"].validate(async valid => {
						if (valid) {
							if(this.type=='cross'){
								var statusColumnName = this.$storage.get('statusColumnName');
								var statusColumnValue = this.$storage.get('statusColumnValue');
								if(statusColumnName!='') {
									var obj = this.$storage.getObj('crossObj');
									if(statusColumnName && !statusColumnName.startsWith("[")) {
										for (var o in obj){
											if(o==statusColumnName){
												obj[o] = statusColumnValue;
											}
										}
										var table = this.$storage.get('crossTable');
										await this.$http({
											url: `${table}/update`,
											method: "post",
											data: obj
										}).then(({ data }) => {});
									}
								}
							}
							await this.$http({
								url: `popupremind/${!this.ruleForm.id ? "save" : "update"}`,
								method: "post",
								data: this.ruleForm
							}).then(async ({ data }) => {
								if (data && data.code === 0) {
									this.$message({
										message: "操作成功",
										type: "success",
										duration: 1500,
										onClose: () => {
											this.parent.showFlag = true;
											this.parent.addOrUpdateFlag = false;
											this.parent.popupremindCrossAddOrUpdateFlag = false;
											this.parent.search();
										}
									});
								} else {
									this.$message.error(data.msg);
								}
							});
						}
					});
			},
			// 获取uuid
			getUUID () {
				return new Date().getTime();
			},
			// 返回
			back() {
				this.parent.showFlag = true;
				this.parent.addOrUpdateFlag = false;
				this.parent.popupremindCrossAddOrUpdateFlag = false;
			},
		}
	};
</script>
