					<img v-else-if="ruleForm.touxiang.substring(0,4)=='http'" class="upload-img" style="margin-right:20px;" v-bind:key="index" :src="ruleForm.touxiang.split(',')[0]" width="100" height="100" @click="imgPreView(ruleForm.tupian.split(',')[0])">
					<img v-else class="upload-img" style="margin-right:20px;" v-bind:key="index" v-for="(item,index) in ruleForm.touxiang.split(',')" :src="$base.url+item" width="100" height="100" @click="imgPreView($base.url+item)">
				</el-form-item>
				<el-form-item class="select" v-if="type!='info'"  label="性别" prop="xingbie" >
					<el-select :disabled="ro.xingbie" v-model="ruleForm.xingbie" placeholder="请选择性别"  filterable>
						<el-option
							v-for="(item,index) in xingbieOptions"
							v-bind:key="index"
							:label="item"
							:value="item">
						</el-option>
					</el-select>
				</el-form-item>
				<el-form-item v-else class="input" label="性别" prop="xingbie" >
					<el-input v-model="ruleForm.xingbie"
						placeholder="性别" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="年龄" prop="nianling" >
					<el-input v-model.number="ruleForm.nianling" placeholder="年龄" clearable  :readonly="ro.nianling"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="年龄" prop="nianling" >
					<el-input v-model="ruleForm.nianling" placeholder="年龄" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="目标院校" prop="mubiaoyuanxiao" >
					<el-input v-model="ruleForm.mubiaoyuanxiao" placeholder="目标院校" clearable  :readonly="ro.mubiaoyuanxiao"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="目标院校" prop="mubiaoyuanxiao" >
					<el-input v-model="ruleForm.mubiaoyuanxiao" placeholder="目标院校" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="班级" prop="banji" >
					<el-input v-model="ruleForm.banji" placeholder="班级" clearable  :readonly="ro.banji"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="班级" prop="banji" >
					<el-input v-model="ruleForm.banji" placeholder="班级" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="备考科目" prop="beikaokemu" >
					<el-input v-model="ruleForm.beikaokemu" placeholder="备考科目" clearable  :readonly="ro.beikaokemu"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="备考科目" prop="beikaokemu" >
					<el-input v-model="ruleForm.beikaokemu" placeholder="备考科目" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="基础水平" prop="jichushuiping" >
					<el-input v-model="ruleForm.jichushuiping" placeholder="基础水平" clearable  :readonly="ro.jichushuiping"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="基础水平" prop="jichushuiping" >
					<el-input v-model="ruleForm.jichushuiping" placeholder="基础水平" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="手机号" prop="mobile" >
					<el-input v-model="ruleForm.mobile" placeholder="手机号" clearable  :readonly="ro.mobile"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="手机号" prop="mobile" >
					<el-input v-model="ruleForm.mobile" placeholder="手机号" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="密保问题" prop="pquestion" >
					<el-input v-model="ruleForm.pquestion" placeholder="密保问题" clearable  :readonly="ro.pquestion"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="密保问题" prop="pquestion" >
					<el-input v-model="ruleForm.pquestion" placeholder="密保问题" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="密保答案" prop="panswer" >
					<el-input v-model="ruleForm.panswer" placeholder="密保答案" clearable  :readonly="ro.panswer"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="密保答案" prop="panswer" >
					<el-input v-model="ruleForm.panswer" placeholder="密保答案" readonly></el-input>
